    "content": "/* shadcn/ui-derived */\nimport * as React from \"react\";\nimport { Drawer as DrawerPrimitive } from \"vaul\";\n\nimport { cn } from \"@/lib/utils\";\nimport { usePortalScopeProps } from \"@/lib/portal-scope\";\nimport {\n  getOverlayTriggerClassName,\n  preventOverlayTriggerSelection,\n} from \"./overlay-trigger.js\";\n\nconst Drawer = ({\n  shouldScaleBackground = false,\n  ...props\n}: React.ComponentProps<typeof DrawerPrimitive.Root>) => (\n  <DrawerPrimitive.Root\n    shouldScaleBackground={shouldScaleBackground}\n    {...props}\n  />\n);\nDrawer.displayName = \"Drawer\";\n\nconst DrawerTrigger = React.forwardRef<\n  React.ComponentRef<typeof DrawerPrimitive.Trigger>,\n  React.ComponentPropsWithoutRef<typeof DrawerPrimitive.Trigger>\n>(({ className, ...props }, ref) => (\n  <DrawerPrimitive.Trigger\n    ref={ref}\n    className={getOverlayTriggerClassName(className)}\n    onMouseDown={preventOverlayTriggerSelection}\n    {...props}\n  />\n));\nDrawerTrigger.displayName = DrawerPrimitive.Trigger.displayName;\n\nconst DrawerPortal = DrawerPrimitive.Portal;\n\nconst DrawerClose = DrawerPrimitive.Close;\n\nconst DrawerOverlay = React.forwardRef<\n  React.ComponentRef<typeof DrawerPrimitive.Overlay>,\n  React.ComponentPropsWithoutRef<typeof DrawerPrimitive.Overlay>\n>(({ className, ...props }, ref) => (\n  <DrawerPrimitive.Overlay\n    ref={ref}\n    // Portaled outside every plugin mount; re-attach the plugin CSS scope\n    // when rendered from a plugin slot (see portal-scope.ts).\n    {...usePortalScopeProps()}\n    className={cn(\n      \"fixed inset-0 z-50 bg-black/40 backdrop-blur-[1px]\",\n      className,\n    )}\n    {...props}\n  />\n));\nDrawerOverlay.displayName = DrawerPrimitive.Overlay.displayName;\n\nconst DrawerContent = React.forwardRef<\n  React.ComponentRef<typeof DrawerPrimitive.Content>,\n  React.ComponentPropsWithoutRef<typeof DrawerPrimitive.Content>\n>(({ className, children, ...props }, ref) => (\n  <DrawerPortal>\n    <DrawerOverlay />\n    <DrawerPrimitive.Content\n      ref={ref}\n      {...usePortalScopeProps()}\n      className={cn(\n        \"fixed inset-x-0 bottom-0 z-50 mt-24 flex max-h-[85dvh] flex-col rounded-t-xl border bg-background\",\n        className,\n      )}\n      {...props}\n    >\n      <DrawerPrimitive.Handle\n        className=\"mx-auto mt-3 mb-1 h-1 w-10 shrink-0 rounded-full bg-muted-foreground/20\"\n      />\n      {children}\n    </DrawerPrimitive.Content>\n  </DrawerPortal>\n));\nDrawerContent.displayName = \"DrawerContent\";\n\nconst DrawerTitle = React.forwardRef<\n  React.ComponentRef<typeof DrawerPrimitive.Title>,\n  React.ComponentPropsWithoutRef<typeof DrawerPrimitive.Title>\n>(({ className, ...props }, ref) => (\n  <DrawerPrimitive.Title\n    ref={ref}\n    className={cn(\n      \"text-lg font-semibold leading-none tracking-tight\",\n      className,\n    )}\n    {...props}\n  />\n));\nDrawerTitle.displayName = DrawerPrimitive.Title.displayName;\n\nconst DrawerDescription = React.forwardRef<\n  React.ComponentRef<typeof DrawerPrimitive.Description>,\n  React.ComponentPropsWithoutRef<typeof DrawerPrimitive.Description>\n>(({ className, ...props }, ref) => (\n  <DrawerPrimitive.Description\n    ref={ref}\n    className={cn(\"text-sm text-muted-foreground\", className)}\n    {...props}\n  />\n));\nDrawerDescription.displayName = DrawerPrimitive.Description.displayName;\n\nexport {\n  Drawer,\n  DrawerPortal,\n  DrawerOverlay,\n  DrawerTrigger,\n  DrawerClose,\n  DrawerContent,\n  DrawerTitle,\n  DrawerDescription,\n};\n"
